        "php": "^7.1|^8.0",
        "paragonie/constant_time_encoding": "^1.0|^2.0|^3.0"
    },
    "require-dev": {
        "phpunit/phpunit": "^7.5.15|^8.5|^9.0",
        "phpstan/phpstan": "^1.9"
    },
    "autoload": {
        "psr-4": {
            "PragmaRX\\Google2FA\\": "src/"
